package org.apache.commons.jxpath.ri.model.dom;

import junit.framework.TestCase;
import org.apache.commons.jxpath.JXPathContext;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;

public class ReproductionTest extends TestCase {
    public void testFindRootWithDescendantAxis() throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.newDocument();
        Element root = doc.createElement("vendor");
        doc.appendChild(root);

        JXPathContext context = JXPathContext.newContext(doc);

        // This should find the root element
        // //vendor expands to /descendant-or-self::node()/child::vendor
        // If the document node is not matched by node(), it won't be in the set
        // to have its children checked.
        Object value = context.getValue("//vendor");

        assertNotNull("Should find vendor element", value);
        assertTrue("Should be an Element", value instanceof Element);
        assertEquals("Should be the root element", root, value);
    }
}

